`,n.jsx(e.p,{children:"Our goal is to minimize the complexity of defining Kubernetes resources for deploying an application. Instead of writing multiple YAML files for Deployments, Services, etc., we will define a single CRD Application that encapsulates all required configurations. The operator will then create the necessary Kubernetes resources automatically."}),`
`,n.jsx(e.p,{children:n.jsx(e.strong,{children:"Requirements for the Example:"})}),`
`,n.jsxs(e.ul,{children:[`
`,n.jsxs(e.li,{children:["The operator shall define a CRD ",n.jsx(e.em,{children:"Application"})," that includes all the configuration of the application."]}),`
`,n.jsx(e.li,{children:"From the CRD, it should create the associated Kubernetes resources such and Deployments, Services"}),`
`,n.jsxs(e.li,{children:["We shall Implement a controller to reconcile the state of ",n.jsx(e.em,{children:"Application"})," resources."]}),`
`,n.jsxs(e.li,{children:["Use the controller to create and manage ",n.jsx(e.em,{children:"Deployments"})," and ",n.jsx(e.em,{children:"Services"}),"."]}),`
